This is my new favorite proof of Sperner’s lemma. In the following app the vertices are slowly morphed to the “cardinal” R, G, B vertices with time while preserving the adjacency relations. Only the rainbow (RGB) triangles are shaded — everything else is left unfilled. Both orientations use the same indigo, distinguished by shading: light, ⟋-hatched triangles are oriented counter-clockwise and dark, ⟍-hatched triangles are oriented clockwise. Can you come up with the proof yourself without peeking below? You can try reducing the number of subdivisions to get a sense of what’s going on.
vertices = [
  {x: 1, y: 0},
  {x: 0.5, y: Math.sqrt(3) / 2},
  {x: 0, y: 0},
];
// Colors every vertex red/green/blue at t=0, moves each vertex linearly
// toward its own color's "cardinal" vertex as t goes from 0 to 1, and
// re-derives the (possibly degenerate) sub-triangles at each t.
function createTriangleMorpher(N, vertices, assignColor) {
  const baryCoords = VM.discreteMath.barycentricTriples(N)

  const buildColorMap = () =&gt; {
    const map = new Map()
    for (const [a, b, c] of baryCoords) {
      map.set(`${a},${b},${c}`, assignColor(a, b, c))
    }
    return map
  }

  const interpolatePoints = (t, colorMap) =&gt; {
    const [A, B, C] = vertices
    const vertexMap = { red: C, green: A, blue: B }

    const morphedPoints = baryCoords.map(([a, b, c]) =&gt; {
      const sum = a + b + c
      const x0 = (a * A.x + b * B.x + c * C.x) / sum
      const y0 = (a * A.y + b * B.y + c * C.y) / sum

      const color = colorMap.get(`${a},${b},${c}`)
      const target = vertexMap[color]

      return {
        x: (1 - t) * x0 + t * target.x,
        y: (1 - t) * y0 + t * target.y,
        color,
        barycentricTriple: [a, b, c]
      }
    })

    const morphedMap = new Map(morphedPoints.map(p =&gt; [p.barycentricTriple.join(','), p]))
    return { morphedPoints, morphedMap }
  }

  const generateSubTriangles = morphedMap =&gt; {
    return VM.discreteMath.subTriangleTriples(N).map(coordinates =&gt; {
      const vertex_colors = coordinates.map(c =&gt; morphedMap.get(c.join(',')).color)
      return { coordinates, vertex_colors }
    })
  }

  return {
    baryCoords,
    buildColorMap,
    interpolatePoints,
    generateSubTriangles
  }
}
// simplerAssignColor deliberately violates Sperner's condition: only the
// three outer vertices get a fixed color, every other point (including
// boundary points) is fully random -- used as a "what goes wrong" foil for
// the correctly-colored triangulation (VM.discreteMath.spernerColor) below.
simplerAssignColor = (a, b, c) =&gt; {
  if (a === 0 && b === 0) return 'red'
  if (b === 0 && c === 0) return 'green'
  if (c === 0 && a === 0) return 'blue'
  return VM.discreteMath.randomColor()
}
fillColorGroups = {
  const group1 = new Set(['RGB', 'GBR', 'BRG'])
  const group2 = new Set(['RBG', 'BGR', 'GRB'])
  return { group1, group2 }
}

// Whether an RGB triangle's vertices, read in their own (counterclockwise)
// order, visit the colors in the same cyclic order as the outer triangle
// ('ccw') or the reverse ('cw'). Returns null for a non-rainbow triangle.
triangleOrientation = vertexColors =&gt; {
  const map = { red: 'R', green: 'G', blue: 'B' }
  const key = vertexColors.map(c =&gt; map[c.toLowerCase()] || '').join('')

  if (fillColorGroups.group1.has(key)) return 'ccw'
  if (fillColorGroups.group2.has(key)) return 'cw'
  return null
}
// One color (the same vivid indigo used for rainbow triangles on every
// Sperner's lemma page) for both orientations -- distinguished by shading,
// not hue: counter-clockwise is a light diagonal hatch sloped one way,
// clockwise is a darker, denser hatch sloped the other way. IDs are unique
// per call since this page renders several plots (teaser + two comparison
// panels) in the same document, and SVG pattern references are resolved
// by document-wide id.
function makeOrientationDefs(ccwId, cwId) {
  const svgNS = "http://www.w3.org/2000/svg";
  const defs = document.createElementNS(svgNS, "defs");
  const color = "rgb(75, 0, 130)";

  function hatch(id, angleDegrees, shadeOpacity) {
    const pattern = document.createElementNS(svgNS, "pattern");
    pattern.setAttribute("id", id);
    pattern.setAttribute("width", "8");
    pattern.setAttribute("height", "8");
    pattern.setAttribute("patternUnits", "userSpaceOnUse");
    pattern.setAttribute("patternTransform", `rotate(${angleDegrees})`);

    const background = document.createElementNS(svgNS, "rect");
    background.setAttribute("width", "8");
    background.setAttribute("height", "8");
    background.setAttribute("fill", color);
    background.setAttribute("fill-opacity", String(shadeOpacity));
    pattern.appendChild(background);

    const stripe = document.createElementNS(svgNS, "line");
    stripe.setAttribute("x1", "0");
    stripe.setAttribute("y1", "0");
    stripe.setAttribute("x2", "0");
    stripe.setAttribute("y2", "8");
    stripe.setAttribute("stroke", color);
    stripe.setAttribute("stroke-width", "3");
    stripe.setAttribute("stroke-opacity", String(Math.min(1, shadeOpacity + 0.35)));
    pattern.appendChild(stripe);

    defs.appendChild(pattern);
  }

  hatch(ccwId, 45, 0.25);   // light shade, ⟋
  hatch(cwId, -45, 0.6);    // dark shade, ⟍

  return defs;
}
function plotTriangles(triangles, morphedPoints, N) {
  // Edges between differently-colored (morphed) vertices, in the same
  // shared gold/teal/orchid palette used elsewhere for mixed edges.
  const mixedEdges = [];
  for (const { a, b } of VM.discreteMath.triangulationEdges(N)) {
    const pa = morphedPoints.morphedMap.get(a.join(','));
    const pb = morphedPoints.morphedMap.get(b.join(','));
    const color = VM.discreteMath.pairColor(pa.color, pb.color);
    if (!color) continue;
    mixedEdges.push({ x1: pa.x, y1: pa.y, x2: pb.x, y2: pb.y, color });
