generateAllTriangles = (N, cpMap) =&gt; {
  const all = [], rg = [], rgb = [];

  for (const coordinates of VM.discreteMath.subTriangleTriples(N)) {
    const data = generateTriangleData(coordinates, cpMap);
    all.push(data);
